+pub const RenderedText = struct {
+    pixels: [][]u8, // Palette index per pixel
+    width: usize,
+    height: usize,
+    allocator: std.mem.Allocator,
+
+    pub fn deinit(self: *RenderedText) void {
+        for (self.pixels) |row| {
+            self.allocator.free(row);
+        }
+        self.allocator.free(self.pixels);
+    }
