+    // prob a bin empty after k trials = (1 - 1/n)**k
+    // p1empty = ((n - 1) / n) ** k
+    const p1empty = std.math.pow(f64, (n - 1.0) / n, k);
+
+    // meanempty = n * p1empty
+    const meanempty = n * p1empty;
+
+    // occupied = n - meanempty
+    const occupied = n - meanempty;
